export const Route = createFileRoute("/lead/$slug/$token")({
  ssr: "data-only",
  component: RouteComponent,
  errorComponent: LeadErrorComponent,
  loader: async ({ context: { queryClient }, params: { slug, token } }) => {
    const options = useGetPublicActionPageQueryOptions({
      actionPageSlug: token,
      accountSlug: slug,
    });
    const actionPage = await queryClient.ensureQueryData(options);
    return { actionPage };
  },
});

// TODO: map the data to better variables first, or change this in the BE model
